arguments.argument:
if global.gamePaused=false
{
  xVel+=xGrav
  yVel+=yGrav
  hspeed=xVel
  vspeed=yVel
  image_angle=direction
  
  if isCollisionTop(1)
    bDestroy=1
  if isCollisionBottom(1)
    bDestroy=1
  if isCollisionLeft(1)
    bDestroy=1
  if isCollisionRight(1)
    bDestroy=1
  
  if bDestroy=1
  {
    instance_destroy()
  }
  if y>room_height+32
    instance_destroy()
}
else
{
  hspeed=0
  vspeed=0
}
